mapper.select:
SELECT * FROM ( SELECT station_name AS stationName, district AS district, MONTH AS month, age_group AS ageGroup, total_use_cnt AS totalUseCnt, -- 이미 SUM 된 결과이므로 그대로 가져옴 ROW_NUMBER() OVER (ORDER BY total_use_cnt DESC) AS rn FROM bike_usage_stats AND MONTH = #{month}
AND district IN #{d}
) WHERE rn BETWEEN #{startRow} AND #{endRow}
